import{_ as a,c as e,o as n,ag as i}from"./chunks/framework.Co20b0ok.js";const k=JSON.parse('{"title":"Linux 下的 Kerberos 认证","description":"","frontmatter":{},"headers":[],"relativePath":"study/domain/Linux 下的 Kerberos 认证.md","filePath":"study/domain/Linux 下的 Kerberos 认证.md"}'),p={name:"study/domain/Linux 下的 Kerberos 认证.md"};function l(t,s,o,r,c,d){return n(),e("div",null,s[0]||(s[0]=[i(`<h1 id="linux-下的-kerberos-认证" tabindex="-1">Linux 下的 Kerberos 认证 <a class="header-anchor" href="#linux-下的-kerberos-认证" aria-label="Permalink to &quot;Linux 下的 Kerberos 认证&quot;">​</a></h1><p><code>KRB5CCNAME</code> 和 <code>/etc/krb5.conf</code> 都与 Kerberos 身份验证相关，但它们的作用不同，下面是它们的详细解释和作用：</p><h3 id="_1-krb5ccname-环境变量" tabindex="-1">1. <strong>KRB5CCNAME</strong> 环境变量 <a class="header-anchor" href="#_1-krb5ccname-环境变量" aria-label="Permalink to &quot;1. **KRB5CCNAME** 环境变量&quot;">​</a></h3><p><code>KRB5CCNAME</code> 是一个环境变量，用于指定 Kerberos 客户端的凭证缓存文件（Credential Cache）的路径。凭证缓存存储了当前用户的 Kerberos 凭证（票据），这些凭证用于身份验证，以便在访问受 Kerberos 保护的资源时进行验证。</p><ul><li><p><strong>用途</strong>：<code>KRB5CCNAME</code> 告诉 Kerberos 客户端程序（如 <code>kinit</code>、<code>klist</code> 等）凭证缓存文件的位置。如果没有设置该环境变量，Kerberos 客户端会使用默认的凭证缓存文件路径（通常是 <code>/tmp/krb5cc_&lt;uid&gt;</code>）。</p></li><li><p><strong>格式</strong>：<code>KRB5CCNAME</code> 的值通常是一个文件路径，例如：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KRB5CCNAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/krb5cc_user</span></span></code></pre></div><p>或者使用其他协议，如：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KRB5CCNAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">FILE:/tmp/krb5cc_user</span></span></code></pre></div></li><li><p><strong>设置方式</strong>： 你可以通过命令行或者在配置文件中设置该环境变量：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KRB5CCNAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/tmp/krb5cc_user</span></span></code></pre></div></li><li><p><strong>用途示例</strong>： 如果你使用 Kerberos 进行身份验证并需要指定特定的凭证缓存路径，可以使用该环境变量。比如，运行 <code>kinit</code> 来获取一个票据时，可以指定该变量：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KRB5CCNAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/tmp/krb5cc_user</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kinit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> username@REALM</span></span></code></pre></div></li></ul><h3 id="_2-etc-krb5-conf-配置文件" tabindex="-1">2. <strong>/etc/krb5.conf 配置文件</strong> <a class="header-anchor" href="#_2-etc-krb5-conf-配置文件" aria-label="Permalink to &quot;2. **/etc/krb5.conf 配置文件**&quot;">​</a></h3><p><code>/etc/krb5.conf</code> 是 Kerberos 客户端的主要配置文件，控制 Kerberos 客户端如何与 KDC（密钥分发中心）进行交互。它包含了有关 Kerberos 域（Realms）、KDC 地址、默认域等信息。</p><ul><li><p><strong>作用</strong>：它提供了 Kerberos 客户端与 KDC 进行通信所需的配置信息，确保客户端能够正确地验证和与域控制器交互。</p></li><li><p><strong>常见配置项</strong>：</p><ul><li><strong>[libdefaults]</strong>：定义默认的 Kerberos 域和其他全局配置。</li><li><strong>[realms]</strong>：定义 Kerberos 域和 KDC 的详细信息。</li><li><strong>[domain_realm]</strong>：域名到 Kerberos 域的映射关系。</li></ul><p>例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ini</span></span>
<span class="line"><span>复制编辑</span></span>
<span class="line"><span>[libdefaults]</span></span>
<span class="line"><span>    default_realm = EXAMPLE.COM</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[realms]</span></span>
<span class="line"><span>    EXAMPLE.COM = {</span></span>
<span class="line"><span>        kdc = kerberos.example.com</span></span>
<span class="line"><span>        admin_server = kerberos.example.com</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[domain_realm]</span></span>
<span class="line"><span>    example.com = EXAMPLE.COM</span></span>
<span class="line"><span>    .example.com = EXAMPLE.COM</span></span></code></pre></div></li><li><p><strong>用途</strong>：它帮助客户端确定目标 Kerberos 域、KDC 和相关配置。例如，它定义了默认的 Kerberos 域 <code>EXAMPLE.COM</code>，并指定了该域的 KDC 地址 <code>kerberos.example.com</code>。</p></li></ul><h3 id="总结对比" tabindex="-1">总结对比： <a class="header-anchor" href="#总结对比" aria-label="Permalink to &quot;总结对比：&quot;">​</a></h3><ul><li><strong>KRB5CCNAME</strong>：是一个环境变量，用于指定 Kerberos 客户端的凭证缓存文件的位置，控制存储 Kerberos 票据的位置。</li><li><strong>/etc/krb5.conf</strong>：是一个配置文件，包含了 Kerberos 客户端的配置信息，如默认的 Kerberos 域、KDC 地址等，确保客户端与 KDC 之间的通信正常进行。</li></ul><h3 id="配置示例" tabindex="-1">配置示例： <a class="header-anchor" href="#配置示例" aria-label="Permalink to &quot;配置示例：&quot;">​</a></h3><p>假设你有以下设置：</p><ul><li><code>/etc/krb5.conf</code> 配置了默认的 Kerberos 域 <code>SOUPEDECODE.LOCAL</code> 和 KDC <code>dc01.soupedecode.local</code>。</li><li>你想使用特定的凭证缓存文件来存储票据，你可以通过设置 <code>KRB5CCNAME</code> 来指定该文件。</li></ul><ol><li><p><strong>/etc/krb5.conf</strong> 配置：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ini</span></span>
<span class="line"><span>复制编辑</span></span>
<span class="line"><span>[libdefaults]</span></span>
<span class="line"><span>    default_realm = SOUPEDECODE.LOCAL</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[realms]</span></span>
<span class="line"><span>    SOUPEDECODE.LOCAL = {</span></span>
<span class="line"><span>        kdc = dc01.soupedecode.local</span></span>
<span class="line"><span>        admin_server = dc01.soupedecode.local</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[domain_realm]</span></span>
<span class="line"><span>    soupedecode.local = SOUPEDECODE.LOCAL</span></span>
<span class="line"><span>    .soupedecode.local = SOUPEDECODE.LOCAL</span></span></code></pre></div></li><li><p><strong>设置 KRB5CCNAME 环境变量</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KRB5CCNAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/tmp/krb5cc_user</span></span></code></pre></div></li><li><p><strong>使用 Kerberos 获取票据</strong>： 通过 <code>kinit</code> 获取票据时，凭证将被存储在指定的缓存文件 <code>/tmp/krb5cc_user</code> 中：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kinit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> username@SOUPEDECODE.LOCAL</span></span></code></pre></div></li></ol>`,14)]))}const b=a(p,[["render",l]]);export{k as __pageData,b as default};
